def reverse_words_preserving_spaces(s: str) -> str:
    words = []
    i = 0
    n = len(s)
    while i < n:
        if s[i] != ' ':
            start = i
            while i < n and s[i] != ' ':
                i += 1
            words.append(s[start:i])
        else:
            i += 1
    words.reverse()
    result = []
    word_index = 0
    i = 0
    while i < n:
        if s[i] == ' ':
            result.append(' ')
            i += 1
        else:
            word = words[word_index]
            result.append(word)
            i += len(word)
            word_index += 1
    return ''.join(result)

def are_anagrams(str1: str, str2: str) -> bool:
    from collections import Counter
    s1 = ''.join(str1.split()).lower()
    s2 = ''.join(str2.split()).lower()
    return Counter(s1) == Counter(s2)

def longest_palindromic_substring(s: str) -> str:
    if not s:
        return ""

    start, max_len = 0, 1

    def expand_around_center(left, right):
        while left >= 0 and right < len(s) and s[left] == s[right]:
            left -= 1
            right += 1
        return left + 1, right - 1

    for i in range(len(s)):
        l1, r1 = expand_around_center(i, i)
        l2, r2 = expand_around_center(i, i + 1)

        if r1 - l1 + 1 > max_len:
            start, max_len = l1, r1 - l1 + 1
        if r2 - l2 + 1 > max_len:
            start, max_len = l2, r2 - l2 + 1

    return s[start:start + max_len]

def run_length_encoding(s: str) -> str:
    if not s:
        return ""
    result = []
    count = 1
    prev = s[0]
    for char in s[1:]:
        if char == prev:
            count += 1
        else:
            result.append(str(count) + prev)
            prev = char
            count = 1
    result.append(str(count) + prev)
    return "".join(result)

def decode_run_length(encoded_str: str) -> str:
    decoded = []
    count = 0
    for char in encoded_str:
        if char.isdigit():
            count = count * 10 + int(char)
        else:
            decoded.append(char * count)
            count = 0
    return ''.join(decoded)

def is_match(s: str, p: str) -> bool:
    memo = {}

    def dp(i, j):
        if (i, j) in memo:
            return memo[(i, j)]
        if j == len(p):
            ans = i == len(s)
        else:
            first_match = i < len(s) and p[j] in {s[i], '.'}
            if j + 1 < len(p) and p[j+1] == '*':
                ans = dp(i, j+2) or (first_match and dp(i+1, j))
            else:
                ans = first_match and dp(i+1, j+1)
        memo[(i, j)] = ans
        return ans

    return dp(0, 0)

def string_permutations_unique(s: str) -> list[str]:
    from collections import Counter
    def backtrack(path, counter):
        if len(path) == len(s):
            result.append("".join(path))
            return
        for ch in counter:
            if counter[ch] > 0:
                path.append(ch)
                counter[ch] -= 1
                backtrack(path, counter)
                counter[ch] += 1
                path.pop()
    result = []
    backtrack([], Counter(s))
    return result

def roman_to_int(s: str) -> int:
    roman_map = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    total = 0
    prev_value = 0
    for char in reversed(s):
        value = roman_map[char]
        if value < prev_value:
            total -= value
        else:
            total += value
        prev_value = value
    return total

def caesar_cipher(text: str, shift: int, encode: bool) -> str:
    if not encode:
        shift = -shift
    result = []
    for char in text:
        if char.isalpha():
            base = ord('A') if char.isupper() else ord('a')
            offset = (ord(char) - base + shift) % 26
            result.append(chr(base + offset))
        else:
            result.append(char)
    return ''.join(result)
